7619 BasicBlock *EpilogueVectorizerMainLoop::emitIterationCountCheck(
7620     BasicBlock *VectorPH, BasicBlock *Bypass, bool ForEpilogue) {
7621   assert(Bypass && "Expected valid bypass basic block.");
7622   Value *Count = getTripCount();
7623   MinProfitableTripCount = ElementCount::getFixed(0);
7624   Value *CheckMinIters = createIterationCountCheck(
7625       VectorPH, ForEpilogue ? EPI.EpilogueVF : EPI.MainLoopVF,
7626       ForEpilogue ? EPI.EpilogueUF : EPI.MainLoopUF);
7627 
7628   BasicBlock *const TCCheckBlock = VectorPH;
7629   if (!ForEpilogue)
7630     TCCheckBlock->setName("vector.main.loop.iter.check");
7631 
7632   // Create new preheader for vector loop.
7633   VectorPH = SplitBlock(TCCheckBlock, TCCheckBlock->getTerminator(),
7634                         static_cast<DominatorTree *>(nullptr), LI, nullptr,
7635                         "vector.ph");
7636   if (ForEpilogue) {
7637     // Save the trip count so we don't have to regenerate it in the
7638     // vec.epilog.iter.check. This is safe to do because the trip count
7639     // generated here dominates the vector epilog iter check.
7640     EPI.TripCount = Count;
7641   } else {
7642     VectorPHVPBB = replaceVPBBWithIRVPBB(VectorPHVPBB, VectorPH);
7643   }
7644 
7645   BranchInst &BI = *BranchInst::Create(Bypass, VectorPH, CheckMinIters);
7646   if (hasBranchWeightMD(*OrigLoop->getLoopLatch()->getTerminator()))
7647     setBranchWeights(BI, MinItersBypassWeights, /*IsExpected=*/false);
7648   ReplaceInstWithInst(TCCheckBlock->getTerminator(), &BI);
7649 
7650   // When vectorizing the main loop, its trip-count check is placed in a new
7651   // block, whereas the overall trip-count check is placed in the VPlan entry
7652   // block. When vectorizing the epilogue loop, its trip-count check is placed
7653   // in the VPlan entry block.
7654   if (!ForEpilogue)
7655     introduceCheckBlockInVPlan(TCCheckBlock);
7656   return TCCheckBlock;
