8718 // Determine how to lower the scalar epilogue, which depends on 1) optimising
8719 // for minimum code-size, 2) predicate compiler options, 3) loop hints forcing
8720 // predication, and 4) a TTI hook that analyses whether the loop is suitable
8721 // for predication.
8722 static ScalarEpilogueLowering getScalarEpilogueLowering(
8723     Function *F, Loop *L, LoopVectorizeHints &Hints, bool OptForSize,
8724     TargetTransformInfo *TTI, TargetLibraryInfo *TLI,
8725     LoopVectorizationLegality &LVL, InterleavedAccessInfo *IAI) {
8726   // 1) OptSize takes precedence over all other options, i.e. if this is set,
8727   // don't look at hints or options, and don't request a scalar epilogue.
8728   if (F->hasOptSize() ||
8729       (OptForSize && Hints.getForce() != LoopVectorizeHints::FK_Enabled))
8730     return CM_ScalarEpilogueNotAllowedOptSize;
8731 
8732   // 2) If set, obey the directives
8733   if (PreferPredicateOverEpilogue.getNumOccurrences()) {
8734     switch (PreferPredicateOverEpilogue) {
8735     case PreferPredicateTy::ScalarEpilogue:
8736       return CM_ScalarEpilogueAllowed;
8737     case PreferPredicateTy::PredicateElseScalarEpilogue:
8738       return CM_ScalarEpilogueNotNeededUsePredicate;
8739     case PreferPredicateTy::PredicateOrDontVectorize:
8740       return CM_ScalarEpilogueNotAllowedUsePredicate;
8741     };
8742   }
8743 
8744   // 3) If set, obey the hints
8745   switch (Hints.getPredicate()) {
8746   case LoopVectorizeHints::FK_Enabled:
8747     return CM_ScalarEpilogueNotNeededUsePredicate;
8748   case LoopVectorizeHints::FK_Disabled:
8749     return CM_ScalarEpilogueAllowed;
8750   };
8751 
8752   // 4) if the TTI hook indicates this is profitable, request predication.
8753   TailFoldingInfo TFI(TLI, &LVL, IAI);
8754   if (TTI->preferPredicateOverEpilogue(&TFI))
8755     return CM_ScalarEpilogueNotNeededUsePredicate;
8756 
8757   return CM_ScalarEpilogueAllowed;
8758 }
