8760 // Process the loop in the VPlan-native vectorization path. This path builds
8761 // VPlan upfront in the vectorization pipeline, which allows to apply
8762 // VPlan-to-VPlan transformations from the very beginning without modifying the
8763 // input LLVM IR.
8764 static bool processLoopInVPlanNativePath(
8765     Loop *L, PredicatedScalarEvolution &PSE, LoopInfo *LI, DominatorTree *DT,
8766     LoopVectorizationLegality *LVL, TargetTransformInfo *TTI,
8767     TargetLibraryInfo *TLI, DemandedBits *DB, AssumptionCache *AC,
8768     OptimizationRemarkEmitter *ORE,
8769     std::function<BlockFrequencyInfo &()> GetBFI, bool OptForSize,
8770     LoopVectorizeHints &Hints, LoopVectorizationRequirements &Requirements) {
8771 
8772   if (isa<SCEVCouldNotCompute>(PSE.getBackedgeTakenCount())) {
8773     LLVM_DEBUG(dbgs() << "LV: cannot compute the outer-loop trip count\n");
8774     return false;
8775   }
8776   assert(EnableVPlanNativePath && "VPlan-native path is disabled.");
8777   Function *F = L->getHeader()->getParent();
8778   InterleavedAccessInfo IAI(PSE, L, DT, LI, LVL->getLAI());
8779 
8780   ScalarEpilogueLowering SEL =
8781       getScalarEpilogueLowering(F, L, Hints, OptForSize, TTI, TLI, *LVL, &IAI);
8782 
8783   LoopVectorizationCostModel CM(SEL, L, PSE, LI, LVL, *TTI, TLI, DB, AC, ORE,
8784                                 GetBFI, F, &Hints, IAI, OptForSize);
8785   // Use the planner for outer loop vectorization.
8786   // TODO: CM is not used at this point inside the planner. Turn CM into an
8787   // optional argument if we don't need it in the future.
8788   LoopVectorizationPlanner LVP(L, LI, DT, TLI, *TTI, LVL, CM, IAI, PSE, Hints,
8789                                ORE);
8790 
8791   // Get user vectorization factor.
8792   ElementCount UserVF = Hints.getWidth();
8793 
8794   CM.collectElementTypesForWidening();
8795 
8796   // Plan how to best vectorize, return the best VF and its cost.
8797   const VectorizationFactor VF = LVP.planInVPlanNativePath(UserVF);
8798 
8799   // If we are stress testing VPlan builds, do not attempt to generate vector
8800   // code. Masked vector code generation support will follow soon.
8801   // Also, do not attempt to vectorize if no vector code will be produced.
8802   if (VPlanBuildStressTest || VectorizationFactor::Disabled() == VF)
8803     return false;
8804 
8805   VPlan &BestPlan = LVP.getPlanFor(VF.Width);
8806 
8807   {
8808     GeneratedRTChecks Checks(PSE, DT, LI, TTI, CM.CostKind);
8809     InnerLoopVectorizer LB(L, PSE, LI, DT, TTI, AC, VF.Width, /*UF=*/1, &CM,
8810                            Checks, BestPlan);
8811     LLVM_DEBUG(dbgs() << "Vectorizing outer loop in \""
8812                       << L->getHeader()->getParent()->getName() << "\"\n");
8813     LVP.addMinimumIterationCheck(BestPlan, VF.Width, /*UF=*/1,
8814                                  VF.MinProfitableTripCount);
8815 
8816     LVP.executePlan(VF.Width, /*UF=*/1, BestPlan, LB, DT, false);
8817   }
8818 
8819   reportVectorization(ORE, L, VF, 1);
8820 
8821   assert(!verifyFunction(*L->getHeader()->getParent(), &dbgs()));
8822   return true;
8823 }
