8825 // Emit a remark if there are stores to floats that required a floating point
8826 // extension. If the vectorized loop was generated with floating point there
8827 // will be a performance penalty from the conversion overhead and the change in
8828 // the vector width.
8829 static void checkMixedPrecision(Loop *L, OptimizationRemarkEmitter *ORE) {
8830   SmallVector<Instruction *, 4> Worklist;
8831   for (BasicBlock *BB : L->getBlocks()) {
8832     for (Instruction &Inst : *BB) {
8833       if (auto *S = dyn_cast<StoreInst>(&Inst)) {
8834         if (S->getValueOperand()->getType()->isFloatTy())
8835           Worklist.push_back(S);
8836       }
8837     }
8838   }
8839 
8840   // Traverse the floating point stores upwards searching, for floating point
8841   // conversions.
8842   SmallPtrSet<const Instruction *, 4> Visited;
8843   SmallPtrSet<const Instruction *, 4> EmittedRemark;
8844   while (!Worklist.empty()) {
8845     auto *I = Worklist.pop_back_val();
8846     if (!L->contains(I))
8847       continue;
8848     if (!Visited.insert(I).second)
8849       continue;
8850 
8851     // Emit a remark if the floating point store required a floating
8852     // point conversion.
8853     // TODO: More work could be done to identify the root cause such as a
8854     // constant or a function return type and point the user to it.
8855     if (isa<FPExtInst>(I) && EmittedRemark.insert(I).second)
8856       ORE->emit([&]() {
8857         return OptimizationRemarkAnalysis(LV_NAME, "VectorMixedPrecision",
8858                                           I->getDebugLoc(), L->getHeader())
8859                << "floating point conversion changes vector width. "
8860                << "Mixed floating point precision requires an up/down "
8861                << "cast that will negatively impact performance.";
8862       });
8863 
8864     for (Use &Op : I->operands())
8865       if (auto *OpI = dyn_cast<Instruction>(Op))
8866         Worklist.push_back(OpI);
8867   }
8868 }
