5544 /// A chain of recipes that form a partial reduction. Matches either
5545 ///   reduction_bin_op (extend (A), accumulator), or
5546 ///   reduction_bin_op (bin_op (extend (A), (extend (B))), accumulator).
5547 struct VPPartialReductionChain {
5548   /// The top-level binary operation that forms the reduction to a scalar
5549   /// after the loop body.
5550   VPWidenRecipe *ReductionBinOp;
5551   /// The extension of each of the inner binary operation's operands.
5552   VPWidenCastRecipe *ExtendA;
5553   VPWidenCastRecipe *ExtendB;
5554   /// The user of the extends that is then reduced.
5555   VPWidenRecipe *BinOp;
5556   unsigned ScaleFactor;
5557 };
