5559 // Helper to transform a partial reduction chain into a partial reduction
5560 // recipe. Assumes profitability has been checked.
5561 static void transformToPartialReduction(const VPPartialReductionChain &Chain,
5562                                         VPTypeAnalysis &TypeInfo, VPlan &Plan,
5563                                         VPReductionPHIRecipe *RdxPhi,
5564                                         RecurKind RK) {
5565   VPWidenRecipe *WidenRecipe = Chain.ReductionBinOp;
5566   assert(WidenRecipe->getNumOperands() == 2 && "Expected binary operation");
5567 
5568   VPValue *BinOp = WidenRecipe->getOperand(0);
5569   VPValue *Accumulator = WidenRecipe->getOperand(1);
5570 
5571   // Swap if needed to ensure Accumulator is the PHI or partial reduction.
5572   if (isa_and_present<VPReductionPHIRecipe, VPReductionRecipe>(BinOp))
5573     std::swap(BinOp, Accumulator);
5574 
5575   // Sub-reductions can be implemented in two ways:
5576   // (1) negate the operand in the vector loop (the default way).
5577   // (2) subtract the reduced value from the init value in the middle block.
5578   // Both ways keep the reduction itself as an 'add' reduction.
5579   //
5580   // The ISD nodes for partial reductions don't support folding the
5581   // sub/negation into its operands because the following is not a valid
5582   // transformation:
5583   //      sub(0, mul(ext(a), ext(b)))
5584   //   -> mul(ext(a), ext(sub(0, b)))
5585   //
5586   // It's therefore better to choose option (2) such that the partial
5587   // reduction is always positive (starting at '0') and to do a final
5588   // subtract in the middle block.
5589   if (WidenRecipe->getOpcode() == Instruction::Sub && RK != RecurKind::Sub) {
5590     VPBuilder Builder(WidenRecipe);
5591     Type *ElemTy = TypeInfo.inferScalarType(BinOp);
5592     auto *Zero = Plan.getConstantInt(ElemTy, 0);
5593     VPIRFlags Flags = WidenRecipe->getUnderlyingInstr()
5594                           ? VPIRFlags(*WidenRecipe->getUnderlyingInstr())
5595                           : VPIRFlags();
5596     auto *NegRecipe = new VPWidenRecipe(Instruction::Sub, {Zero, BinOp}, Flags,
5597                                         VPIRMetadata(), DebugLoc::getUnknown());
5598     Builder.insert(NegRecipe);
5599     BinOp = NegRecipe;
5600   }
5601 
5602   // Check if WidenRecipe is the final result of the reduction. If so look
5603   // through selects for predicated reductions.
5604   VPValue *Cond = nullptr;
5605   VPValue *ExitValue = cast_or_null<VPInstruction>(vputils::findUserOf(
5606       WidenRecipe,
5607       m_Select(m_VPValue(Cond), m_Specific(WidenRecipe), m_Specific(RdxPhi))));
5608   bool IsLastInChain = RdxPhi->getBackedgeValue() == WidenRecipe ||
5609                        RdxPhi->getBackedgeValue() == ExitValue;
5610   assert((!ExitValue || IsLastInChain) &&
5611          "if we found ExitValue, it must match RdxPhi's backedge value");
5612 
5613   Type *PhiType = TypeInfo.inferScalarType(RdxPhi);
5614   RecurKind RdxKind =
5615       PhiType->isFloatingPointTy() ? RecurKind::FAdd : RecurKind::Add;
5616   auto *PartialRed = new VPReductionRecipe(
5617       RdxKind,
5618       RdxKind == RecurKind::FAdd ? WidenRecipe->getFastMathFlags()
5619                                  : FastMathFlags(),
5620       WidenRecipe->getUnderlyingInstr(), Accumulator, BinOp, Cond,
5621       RdxUnordered{/*VFScaleFactor=*/Chain.ScaleFactor});
5622   PartialRed->insertBefore(WidenRecipe);
5623 
5624   if (Cond)
5625     ExitValue->replaceAllUsesWith(PartialRed);
5626   WidenRecipe->replaceAllUsesWith(PartialRed);
5627 
5628   // We only need to update the PHI node once, which is when we find the
5629   // last reduction in the chain.
5630   if (!IsLastInChain)
5631     return;
5632 
5633   // Scale the PHI and ReductionStartVector by the VFScaleFactor
5634   assert(RdxPhi->getVFScaleFactor() == 1 && "scale factor must not be set");
5635   RdxPhi->setVFScaleFactor(Chain.ScaleFactor);
5636 
5637   auto *StartInst = cast<VPInstruction>(RdxPhi->getStartValue());
5638   assert(StartInst->getOpcode() == VPInstruction::ReductionStartVector);
5639   auto *NewScaleFactor = Plan.getConstantInt(32, Chain.ScaleFactor);
5640   StartInst->setOperand(2, NewScaleFactor);
5641 
5642   // If this is the last value in a sub-reduction chain, then update the PHI
5643   // node to start at `0` and update the reduction-result to subtract from
5644   // the PHI's start value.
5645   if (RK != RecurKind::Sub)
5646     return;
5647 
5648   VPValue *OldStartValue = StartInst->getOperand(0);
5649   StartInst->setOperand(0, StartInst->getOperand(1));
5650 
5651   // Replace reduction_result by 'sub (startval, reductionresult)'.
5652   VPInstruction *RdxResult = vputils::findComputeReductionResult(RdxPhi);
5653   assert(RdxResult && "Could not find reduction result");
5654 
5655   VPBuilder Builder = VPBuilder::getToInsertAfter(RdxResult);
5656   constexpr unsigned SubOpc = Instruction::BinaryOps::Sub;
5657   VPInstruction *NewResult = Builder.createNaryOp(
5658       SubOpc, {OldStartValue, RdxResult}, VPIRFlags::getDefaultFlags(SubOpc),
5659       RdxPhi->getDebugLoc());
5660   RdxResult->replaceUsesWithIf(
5661       NewResult,
5662       [&NewResult](VPUser &U, unsigned Idx) { return &U != NewResult; });
5663 }
