5665 /// Check if a partial reduction chain is is supported by the target (i.e. does
5666 /// not have an invalid cost) for the given VF range. Clamps the range and
5667 /// returns true if profitable for any VF.
5668 static bool isValidPartialReduction(const VPPartialReductionChain &Chain,
5669                                     Type *PhiType, VPCostContext &CostCtx,
5670                                     VFRange &Range) {
5671   auto GetExtInfo = [&CostCtx](VPWidenCastRecipe *Ext)
5672       -> std::pair<Type *, TargetTransformInfo::PartialReductionExtendKind> {
5673     if (!Ext)
5674       return {nullptr, TargetTransformInfo::PR_None};
5675     Type *ExtOpType = CostCtx.Types.inferScalarType(Ext->getOperand(0));
5676     auto ExtKind = TargetTransformInfo::getPartialReductionExtendKind(
5677         static_cast<Instruction::CastOps>(Ext->getOpcode()));
5678     return {ExtOpType, ExtKind};
5679   };
5680   auto ExtInfoA = GetExtInfo(Chain.ExtendA);
5681   auto ExtInfoB = GetExtInfo(Chain.ExtendB);
5682   Type *ExtOpTypeA = ExtInfoA.first;
5683   Type *ExtOpTypeB = ExtInfoB.first;
5684   auto ExtKindA = ExtInfoA.second;
5685   auto ExtKindB = ExtInfoB.second;
5686 
5687   // If ExtendB is nullptr but there's a separate BinOp, the second operand
5688   // was a constant that can use the same extend kind as the first.
5689   if (!Chain.ExtendB && Chain.BinOp && Chain.BinOp != Chain.ReductionBinOp) {
5690     const APInt *Const = nullptr;
5691     for (VPValue *Op : Chain.BinOp->operands()) {
5692       if (match(Op, m_APInt(Const)))
5693         break;
5694     }
5695     if (!Const || !canConstantBeExtended(Const, ExtOpTypeA, ExtKindA))
5696       return false;
5697     ExtOpTypeB = ExtOpTypeA;
5698     ExtKindB = ExtKindA;
5699   }
5700 
5701   std::optional<unsigned> BinOpc =
5702       (Chain.BinOp && Chain.BinOp != Chain.ReductionBinOp)
5703           ? std::make_optional(Chain.BinOp->getOpcode())
5704           : std::nullopt;
5705   VPWidenRecipe *WidenRecipe = Chain.ReductionBinOp;
5706   return LoopVectorizationPlanner::getDecisionAndClampRange(
5707       [&](ElementCount VF) {
5708         return CostCtx.TTI
5709             .getPartialReductionCost(
5710                 WidenRecipe->getOpcode(), ExtOpTypeA, ExtOpTypeB, PhiType, VF,
5711                 ExtKindA, ExtKindB, BinOpc, CostCtx.CostKind,
5712                 PhiType->isFloatingPointTy()
5713                     ? std::optional{WidenRecipe->getFastMathFlags()}
5714                     : std::nullopt)
5715             .isValid();
5716       },
5717       Range);
5718 }
