5720 /// Examines reduction operations to see if the target can use a cheaper
5721 /// operation with a wider per-iteration input VF and narrower PHI VF.
5722 /// Recursively calls itself to identify chained scaled reductions.
5723 /// Returns true if this invocation added an entry to Chains, otherwise false.
5724 static bool
5725 getScaledReductions(VPSingleDefRecipe *RedPhiR, VPValue *PrevValue,
5726                     SmallVectorImpl<VPPartialReductionChain> &Chains,
5727                     VPCostContext &CostCtx, VFRange &Range) {
5728   auto *UpdateR = dyn_cast<VPWidenRecipe>(PrevValue);
5729   if (!UpdateR || !Instruction::isBinaryOp(UpdateR->getOpcode()))
5730     return false;
5731 
5732   VPValue *Op = UpdateR->getOperand(0);
5733   VPValue *PhiOp = UpdateR->getOperand(1);
5734   if (Op == RedPhiR)
5735     std::swap(Op, PhiOp);
5736 
5737   // If Op is an extend, then it's still a valid partial reduction if the
5738   // extended mul fulfills the other requirements.
5739   // For example, reduce.add(ext(mul(ext(A), ext(B)))) is still a valid partial
5740   // reduction since the inner extends will be widened. We already have oneUse
5741   // checks on the inner extends so widening them is safe.
5742   std::optional<TTI::PartialReductionExtendKind> OuterExtKind;
5743   if (match(Op, m_ZExtOrSExt(m_Mul(m_VPValue(), m_VPValue()))) ||
5744       match(Op, m_FPExt(m_FMul(m_VPValue(), m_VPValue())))) {
5745     auto *CastRecipe = dyn_cast<VPWidenCastRecipe>(Op);
5746     if (!CastRecipe)
5747       return false;
5748     auto CastOp = static_cast<Instruction::CastOps>(CastRecipe->getOpcode());
5749     OuterExtKind = TTI::getPartialReductionExtendKind(CastOp);
5750     Op = CastRecipe->getOperand(0);
5751   }
5752 
5753   // Try and get a scaled reduction from the first non-phi operand.
5754   // If one is found, we use the discovered reduction instruction in
5755   // place of the accumulator for costing.
5756   if (getScaledReductions(RedPhiR, Op, Chains, CostCtx, Range)) {
5757     RedPhiR = Chains.rbegin()->ReductionBinOp;
5758     Op = UpdateR->getOperand(0);
5759     PhiOp = UpdateR->getOperand(1);
5760     if (Op == RedPhiR)
5761       std::swap(Op, PhiOp);
5762   }
5763   if (RedPhiR != PhiOp)
5764     return false;
5765 
5766   // If the update is a binary op, check both of its operands to see if
5767   // they are extends. Otherwise, see if the update comes directly from an
5768   // extend.
5769   VPWidenCastRecipe *CastRecipes[2] = {nullptr};
5770 
5771   // Match extends and populate CastRecipes. Returns false if matching fails.
5772   auto MatchExtends = [OuterExtKind,
5773                        &CastRecipes](ArrayRef<VPValue *> Operands) {
5774     assert(Operands.size() <= 2 && "expected at most 2 operands");
