5254 static VPValue *tryToComputeEndValueForInduction(VPWidenInductionRecipe *WideIV,
5255                                                  VPBuilder &VectorPHBuilder,
5256                                                  VPTypeAnalysis &TypeInfo,
5257                                                  VPValue *VectorTC) {
5258   auto *WideIntOrFp = dyn_cast<VPWidenIntOrFpInductionRecipe>(WideIV);
5259   // Truncated wide inductions resume from the last lane of their vector value
5260   // in the last vector iteration which is handled elsewhere.
5261   if (WideIntOrFp && WideIntOrFp->getTruncInst())
5262     return nullptr;
5263 
5264   VPIRValue *Start = WideIV->getStartValue();
5265   VPValue *Step = WideIV->getStepValue();
5266   const InductionDescriptor &ID = WideIV->getInductionDescriptor();
5267   VPValue *EndValue = VectorTC;
5268   if (!WideIntOrFp || !WideIntOrFp->isCanonical()) {
5269     EndValue = VectorPHBuilder.createDerivedIV(
5270         ID.getKind(), dyn_cast_or_null<FPMathOperator>(ID.getInductionBinOp()),
5271         Start, VectorTC, Step);
5272   }
5273 
5274   // EndValue is derived from the vector trip count (which has the same type as
5275   // the widest induction) and thus may be wider than the induction here.
5276   Type *ScalarTypeOfWideIV = TypeInfo.inferScalarType(WideIV);
5277   if (ScalarTypeOfWideIV != TypeInfo.inferScalarType(EndValue)) {
5278     EndValue = VectorPHBuilder.createScalarCast(Instruction::Trunc, EndValue,
5279                                                 ScalarTypeOfWideIV,
5280                                                 WideIV->getDebugLoc());
5281   }
5282 
5283   return EndValue;
5284 }
