5336 void VPlanTransforms::addExitUsersForFirstOrderRecurrences(VPlan &Plan,
5337                                                            VFRange &Range) {
5338   VPRegionBlock *VectorRegion = Plan.getVectorLoopRegion();
5339   auto *ScalarPHVPBB = Plan.getScalarPreheader();
