5348   for (auto &HeaderPhi : VectorRegion->getEntryBasicBlock()->phis()) {
5349     auto *FOR = dyn_cast<VPFirstOrderRecurrencePHIRecipe>(&HeaderPhi);
5350     if (!FOR)
