5353     assert(VectorRegion->getSingleSuccessor() == Plan.getMiddleBlock() &&
5354            "Cannot handle loops with uncountable early exits");
5355 
5356     // This is the second phase of vectorizing first-order recurrences, creating
5357     // extract for users outside the loop. An overview of the transformation is
5358     // described below. Suppose we have the following loop with some use after
5359     // the loop of the last a[i-1],
5360     //
5361     //   for (int i = 0; i < n; ++i) {
5362     //     t = a[i - 1];
5363     //     b[i] = a[i] - t;
5364     //   }
5365     //   use t;
5366     //
5367     // There is a first-order recurrence on "a". For this loop, the shorthand
5368     // scalar IR looks like:
5369     //
5370     //   scalar.ph:
5371     //     s.init = a[-1]
5372     //     br scalar.body
5373     //
5374     //   scalar.body:
5375     //     i = phi [0, scalar.ph], [i+1, scalar.body]
5376     //     s1 = phi [s.init, scalar.ph], [s2, scalar.body]
5377     //     s2 = a[i]
5378     //     b[i] = s2 - s1
5379     //     br cond, scalar.body, exit.block
5380     //
5381     //   exit.block:
5382     //     use = lcssa.phi [s1, scalar.body]
5383     //
5384     // In this example, s1 is a recurrence because it's value depends on the
5385     // previous iteration. In the first phase of vectorization, we created a
5386     // VPFirstOrderRecurrencePHIRecipe v1 for s1. Now we create the extracts
5387     // for users in the scalar preheader and exit block.
5388     //
5389     //   vector.ph:
5390     //     v_init = vector(..., ..., ..., a[-1])
5391     //     br vector.body
5392     //
5393     //   vector.body
5394     //     i = phi [0, vector.ph], [i+4, vector.body]
5395     //     v1 = phi [v_init, vector.ph], [v2, vector.body]
5396     //     v2 = a[i, i+1, i+2, i+3]
5397     //     b[i] = v2 - v1
5398     //     // Next, third phase will introduce v1' = splice(v1(3), v2(0, 1, 2))
5399     //     b[i, i+1, i+2, i+3] = v2 - v1
5400     //     br cond, vector.body, middle.block
5401     //
5402     //   middle.block:
5403     //     vector.recur.extract.for.phi = v2(2)
5404     //     vector.recur.extract = v2(3)
5405     //     br cond, scalar.ph, exit.block
5406     //
5407     //   scalar.ph:
5408     //     scalar.recur.init = phi [vector.recur.extract, middle.block],
5409     //                             [s.init, otherwise]
5410     //     br scalar.body
5411     //
5412     //   scalar.body:
5413     //     i = phi [0, scalar.ph], [i+1, scalar.body]
5414     //     s1 = phi [scalar.recur.init, scalar.ph], [s2, scalar.body]
5415     //     s2 = a[i]
5416     //     b[i] = s2 - s1
5417     //     br cond, scalar.body, exit.block
5418     //
5419     //   exit.block:
5420     //     lo = lcssa.phi [s1, scalar.body],
5421     //                    [vector.recur.extract.for.phi, middle.block]
5422     //
5423     // Now update VPIRInstructions modeling LCSSA phis in the exit block.
5424     // Extract the penultimate value of the recurrence and use it as operand for
5425     // the VPIRInstruction modeling the phi.
5426     for (VPRecipeBase &R : make_early_inc_range(
5427              make_range(MiddleVPBB->getFirstNonPhi(), MiddleVPBB->end()))) {
5428       if (!match(&R, m_ExtractLastLaneOfLastPart(m_Specific(FOR))))
5429         continue;
5430 
5431       // For VF vscale x 1, if vscale = 1, we are unable to extract the
5432       // penultimate value of the recurrence. Instead we rely on the existing
5433       // extract of the last element from the result of
5434       // VPInstruction::FirstOrderRecurrenceSplice.
5435       // TODO: Consider vscale_range info and UF.
5436       if (LoopVectorizationPlanner::getDecisionAndClampRange(IsScalableOne,
5437                                                              Range))
5438         return;
5439       VPValue *PenultimateElement = MiddleBuilder.createNaryOp(
5440           VPInstruction::ExtractPenultimateElement, FOR->getBackedgeValue(), {},
5441           "vector.recur.extract.for.phi");
5442       cast<VPInstruction>(&R)->replaceAllUsesWith(PenultimateElement);
5443     }
5444   }
