1695 /// VPWidenRecipe is a recipe for producing a widened instruction using the
1696 /// opcode and operands of the recipe. This recipe covers most of the
1697 /// traditional vectorization cases where each recipe transforms into a
1698 /// vectorized version of itself.
1699 class LLVM_ABI_FOR_TEST VPWidenRecipe : public VPRecipeWithIRFlags,
1700                                         public VPIRMetadata {
1701   unsigned Opcode;
1702 
1703 public:
1704   VPWidenRecipe(Instruction &I, ArrayRef<VPValue *> Operands,
1705                 const VPIRFlags &Flags = {}, const VPIRMetadata &Metadata = {},
1706                 DebugLoc DL = {})
1707       : VPRecipeWithIRFlags(VPRecipeBase::VPWidenSC, Operands, Flags, DL),
1708         VPIRMetadata(Metadata), Opcode(I.getOpcode()) {
1709     setUnderlyingValue(&I);
1710   }
1711 
1712   VPWidenRecipe(unsigned Opcode, ArrayRef<VPValue *> Operands,
1713                 const VPIRFlags &Flags = {}, const VPIRMetadata &Metadata = {},
1714                 DebugLoc DL = {})
1715       : VPRecipeWithIRFlags(VPRecipeBase::VPWidenSC, Operands, Flags, DL),
1716         VPIRMetadata(Metadata), Opcode(Opcode) {}
1717 
1718   ~VPWidenRecipe() override = default;
1719 
1720   VPWidenRecipe *clone() override {
1721     if (auto *UV = getUnderlyingValue())
1722       return new VPWidenRecipe(*cast<Instruction>(UV), operands(), *this, *this,
1723                                getDebugLoc());
1724     return new VPWidenRecipe(Opcode, operands(), *this, *this, getDebugLoc());
1725   }
1726 
1727   VP_CLASSOF_IMPL(VPRecipeBase::VPWidenSC)
1728 
1729   /// Produce a widened instruction using the opcode and operands of the recipe,
1730   /// processing State.VF elements.
1731   void execute(VPTransformState &State) override;
1732 
1733   /// Return the cost of this VPWidenRecipe.
1734   InstructionCost computeCost(ElementCount VF,
1735                               VPCostContext &Ctx) const override;
1736 
1737   unsigned getOpcode() const { return Opcode; }
1738 
1739 protected:
1740 #if !defined(NDEBUG) || defined(LLVM_ENABLE_DUMP)
1741   /// Print the recipe.
1742   void printRecipe(raw_ostream &O, const Twine &Indent,
1743                    VPSlotTracker &SlotTracker) const override;
1744 #endif
1745 
1746   /// Returns true if the recipe only uses the first lane of operand \p Op.
1747   bool usesFirstLaneOnly(const VPValue *Op) const override {
1748     assert(is_contained(operands(), Op) &&
1749            "Op must be an operand of the recipe");
1750     return Opcode == Instruction::Select && Op == getOperand(0) &&
1751            Op->isDefinedOutsideLoopRegions();
1752   }
1753 };
